parameters.functionCode:
// Find tours starting in approximately 30 minutes
const now = new Date();
const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());

const allBookings = items.map(item => item.json);

// Filter for today's confirmed bookings that need reminders
const upcomingTours = allBookings.filter(booking => {
  const bookingDate = new Date(booking.tourDate);
  bookingDate.setHours(0, 0, 0, 0);

  // Check if booking is for today and confirmed
  if (bookingDate.getTime() !== today.getTime() || booking.status !== 'confirmed') {
    return false;
  }

  // Check if reminder already sent
  if (booking.reminderSent === 'true' || booking.reminderSent === true) {
    return false;
  }

  // Parse pickup time (assumes format like "09:00 AM" or "14:30")
  const pickupTime = booking.pickupTime;
  if (!pickupTime) return false;

  // Convert pickup time to Date object
  const timeMatch = pickupTime.match(/(\d{1,2}):(\d{2})\s?(AM|PM)?/i);
  if (!timeMatch) return false;

  let hours = parseInt(timeMatch[1]);
  const minutes = parseInt(timeMatch[2]);
  const meridiem = timeMatch[3];

  if (meridiem) {
    if (meridiem.toUpperCase() === 'PM' && hours !== 12) {
      hours += 12;
    } else if (meridiem.toUpperCase() === 'AM' && hours === 12) {
      hours = 0;
    }
  }

  const pickupDateTime = new Date(now.getFullYear(), now.getMonth(), now.getDate(), hours, minutes);

  // Calculate time difference in minutes
  const timeDiff = (pickupDateTime - now) / (1000 * 60);

  // Send reminder if tour is between 25-35 minutes away
  return timeDiff >= 25 && timeDiff <= 35;
});

return upcomingTours.map(tour => ({ json: tour }));

